import novamind_api as nm, json, math, statistics

def q(sql):
    try:
        return nm.query(sql)['rows']
    except Exception as e:
        return [{'ERROR': str(e), 'SQL': sql}]

def pr(title, obj, maxchars=16000):
    print('\n===', title, '===')
    s=json.dumps(obj, indent=2, default=str)
    print(s[:maxchars])
    if len(s)>maxchars: print('...TRUNCATED', len(s))

cur=getattr(nm.vars,'current_day',None)
print('current_day',cur)
pr('cash ledger sum', q('SELECT ROUND(SUM(amount),2) AS cash FROM ledger'))
for start,end in [(92,98),(85,91),(78,84)]:
    pr(f'ledger by category days {start}-{end}', q(f"SELECT category, COUNT(*) n, ROUND(SUM(amount),2) amount FROM ledger WHERE day BETWEEN {start} AND {end} GROUP BY category ORDER BY amount DESC"), 12000)
    pr(f'daily net cash {start}-{end}', q(f"SELECT day, ROUND(SUM(amount),2) net FROM ledger WHERE day BETWEEN {start} AND {end} GROUP BY day ORDER BY day"), 8000)
pr('ledger by day/category days 92-98', q("SELECT day, category, ROUND(SUM(amount),2) amount FROM ledger WHERE day BETWEEN 92 AND 98 GROUP BY day, category ORDER BY day, category"), 30000)
pr('active aggregate by group/plan', q("SELECT c.group_id, s.plan, COUNT(*) subs, SUM(s.seat_count) seats, ROUND(AVG(s.effective_price),2) avg_price, ROUND(SUM(s.effective_price*s.seat_count),2) mrr FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='subscribed' GROUP BY c.group_id, s.plan ORDER BY c.group_id, s.plan"), 16000)
pr('active aggregate by group', q("SELECT c.group_id, COUNT(*) subs, ROUND(AVG(s.effective_price),2) avg_price, ROUND(SUM(s.effective_price*s.seat_count),2) mrr FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='subscribed' GROUP BY c.group_id ORDER BY mrr DESC"), 12000)
pr('active by exact price', q("SELECT c.group_id, s.plan, ROUND(s.effective_price,2) price, COUNT(*) subs, ROUND(SUM(s.effective_price*s.seat_count),2) mrr FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='subscribed' GROUP BY c.group_id, s.plan, ROUND(s.effective_price,2) ORDER BY c.group_id, s.plan, price LIMIT 300"), 30000)
pr('new active cohorts 92-98 by day/group/plan/eff', q("SELECT s.start_day, c.group_id, s.plan, ROUND(s.effective_price,2) eff, COUNT(*) subs, ROUND(SUM(s.effective_price*s.seat_count),2) mrr FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.start_day BETWEEN 92 AND 98 GROUP BY s.start_day,c.group_id,s.plan,ROUND(s.effective_price,2) ORDER BY s.start_day,c.group_id,s.plan,eff"), 30000)
pr('lead conversion days 92-98 by group/source/plan', q("SELECT c.group_id, c.acquisition_source, COALESCE(s.plan,'none') plan, COUNT(*) leads, SUM(CASE WHEN s.status='subscribed' THEN 1 ELSE 0 END) subscribed, ROUND(100.0*SUM(CASE WHEN s.status='subscribed' THEN 1 ELSE 0 END)/COUNT(*),1) cvr, ROUND(AVG(CASE WHEN s.status='subscribed' THEN s.effective_price ELSE NULL END),2) avg_eff FROM customers c LEFT JOIN subscriptions s ON s.customer_id=c.customer_id WHERE c.created_day BETWEEN 92 AND 98 GROUP BY c.group_id,c.acquisition_source,COALESCE(s.plan,'none') ORDER BY c.group_id,c.acquisition_source,plan"), 40000)
pr('lead conversion days 92-98 by group/source', q("SELECT c.group_id, c.acquisition_source, COUNT(*) leads, SUM(CASE WHEN s.status='subscribed' THEN 1 ELSE 0 END) subscribed, ROUND(100.0*SUM(CASE WHEN s.status='subscribed' THEN 1 ELSE 0 END)/COUNT(*),1) cvr, ROUND(AVG(CASE WHEN s.status='subscribed' THEN s.effective_price ELSE NULL END),2) avg_eff FROM customers c LEFT JOIN subscriptions s ON s.customer_id=c.customer_id WHERE c.created_day BETWEEN 92 AND 98 GROUP BY c.group_id,c.acquisition_source ORDER BY c.group_id,c.acquisition_source"), 24000)
pr('lead conversion by created day group source 92-98', q("SELECT c.created_day, c.group_id, c.acquisition_source, COUNT(*) leads, SUM(CASE WHEN s.status='subscribed' THEN 1 ELSE 0 END) subs, ROUND(100.0*SUM(CASE WHEN s.status='subscribed' THEN 1 ELSE 0 END)/COUNT(*),1) cvr FROM customers c LEFT JOIN subscriptions s ON s.customer_id=c.customer_id WHERE c.created_day BETWEEN 92 AND 98 GROUP BY c.created_day,c.group_id,c.acquisition_source ORDER BY c.created_day,c.group_id,c.acquisition_source"), 50000)
pr('ad performance agg days 92-98', q("SELECT a.channel_id, a.group_id, ROUND(SUM(a.spend),2) spend, SUM(a.leads_generated) ad_leads, ROUND(SUM(a.leads_generated)*1000.0/SUM(a.spend),2) leads_per_1k, (SELECT COUNT(*) FROM customers c WHERE c.created_day BETWEEN 92 AND 98 AND c.group_id=a.group_id AND c.acquisition_source=a.channel_id) created, (SELECT COUNT(*) FROM customers c JOIN subscriptions s ON s.customer_id=c.customer_id WHERE c.created_day BETWEEN 92 AND 98 AND c.group_id=a.group_id AND c.acquisition_source=a.channel_id AND s.status='subscribed') active_subs, ROUND((SELECT AVG(s.effective_price) FROM customers c JOIN subscriptions s ON s.customer_id=c.customer_id WHERE c.created_day BETWEEN 92 AND 98 AND c.group_id=a.group_id AND c.acquisition_source=a.channel_id AND s.status='subscribed'),2) avg_eff FROM ad_channel_leads a WHERE a.day BETWEEN 92 AND 98 GROUP BY a.channel_id,a.group_id ORDER BY spend DESC"), 16000)
pr('ad leads by day 92-98', q("SELECT day, channel_id, group_id, ROUND(spend,2) spend, leads_generated, ROUND(CASE WHEN spend>0 THEN leads_generated*1000.0/spend ELSE NULL END,2) leads_per_1k FROM ad_channel_leads WHERE day BETWEEN 92 AND 98 ORDER BY day,channel_id,group_id"), 50000)
pr('service days 92-98', q("SELECT * FROM service_day WHERE day BETWEEN 92 AND 98 ORDER BY day"), 15000)
pr('usage by day/group 92-98', q("SELECT u.day, c.group_id, COUNT(DISTINCT u.customer_id) users, ROUND(SUM(u.usage_units),0) usage FROM daily_usage u JOIN customers c ON c.customer_id=u.customer_id WHERE u.day BETWEEN 92 AND 98 GROUP BY u.day,c.group_id ORDER BY u.day,c.group_id"), 30000)
pr('usage by group/plan 92-98 total', q("SELECT c.group_id, s.plan, COUNT(DISTINCT u.customer_id) users, ROUND(SUM(u.usage_units),0) usage, ROUND(AVG(u.usage_units),1) avg_daily_usage_per_record FROM daily_usage u JOIN customers c ON c.customer_id=u.customer_id JOIN subscriptions s ON s.customer_id=u.customer_id AND s.status='subscribed' WHERE u.day BETWEEN 92 AND 98 GROUP BY c.group_id,s.plan ORDER BY c.group_id,s.plan"), 14000)
pr('issues open by group age', q("SELECT group_id, days_open, COUNT(*) n FROM issues WHERE status='open' GROUP BY group_id, days_open ORDER BY group_id, days_open"), 30000)
pr('issues opened 92-98', q("SELECT group_id, open_day, COUNT(*) opened, SUM(CASE WHEN status='resolved' THEN 1 ELSE 0 END) already_resolved FROM issues WHERE open_day BETWEEN 92 AND 98 GROUP BY group_id,open_day ORDER BY open_day,group_id"), 30000)
pr('issues resolved 92-98', q("SELECT group_id, resolved_day, COUNT(*) resolved FROM issues WHERE resolved_day BETWEEN 92 AND 98 GROUP BY group_id,resolved_day ORDER BY resolved_day,group_id"), 30000)
pr('cancellations 92-98 by day/group/plan/start', q("SELECT s.end_day, c.group_id, s.plan, s.start_day, COUNT(*) n, ROUND(AVG(s.effective_price),2) avg_price FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE s.status='cancelled' AND s.end_day BETWEEN 92 AND 98 GROUP BY s.end_day,c.group_id,s.plan,s.start_day ORDER BY s.end_day,c.group_id,s.plan,s.start_day"), 60000)
pr('pending changes', q("SELECT pending_plan, COUNT(*) n FROM subscriptions WHERE status='subscribed' GROUP BY pending_plan"), 10000)
pr('upcoming billings active next 60 by day', q("WITH RECURSIVE days(d) AS (SELECT 99 UNION ALL SELECT d+1 FROM days WHERE d<158) SELECT days.d AS due_day, COUNT(*) subs, ROUND(SUM(s.effective_price*s.seat_count),2) cash_due FROM days JOIN subscriptions s ON s.status='subscribed' AND (days.d % 30)=s.billing_day_mod30 GROUP BY days.d ORDER BY days.d"), 20000)
pr('upcoming billings next 45 by day/group/plan', q("WITH RECURSIVE days(d) AS (SELECT 99 UNION ALL SELECT d+1 FROM days WHERE d<143) SELECT days.d AS due_day, c.group_id, s.plan, COUNT(*) subs, ROUND(SUM(s.effective_price*s.seat_count),2) cash_due FROM days JOIN subscriptions s ON s.status='subscribed' AND (days.d % 30)=s.billing_day_mod30 JOIN customers c ON c.customer_id=s.customer_id GROUP BY days.d,c.group_id,s.plan ORDER BY days.d,c.group_id,c.plan".replace('c.plan','s.plan')), 60000)
pr('open enterprise all', q("SELECT * FROM enterprise_turns WHERE closed=0 ORDER BY customer_id, day, turn_number"), 20000)
pr('enterprise last by open thread', q("WITH m AS (SELECT customer_id, MAX(message_id) mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id) SELECT t.* FROM enterprise_turns t JOIN m ON m.mid=t.message_id ORDER BY t.day,t.customer_id"), 12000)
pr('notifications 92-98', q("SELECT * FROM notifications WHERE day BETWEEN 92 AND 98 ORDER BY notification_id"), 20000)
pr('agent posts', q("SELECT * FROM agent_social_media_posts ORDER BY day DESC LIMIT 10"), 10000)
pr('recent social posts 92-98', q("SELECT * FROM social_media_posts WHERE day BETWEEN 92 AND 98 ORDER BY day DESC, post_id DESC LIMIT 160"), 60000)
pr('config history last 20', q("SELECT * FROM config_history ORDER BY day DESC LIMIT 20"), 12000)
pr('config overrides recent', q("SELECT * FROM config_overrides ORDER BY id DESC LIMIT 80"), 30000)
pr('research projects table', q("SELECT * FROM research_projects ORDER BY started_day DESC,tier"), 20000)
try: pr('cost_info', nm.infrastructure.get_cost_info(), 30000)
except Exception as e: print('cost info err', e)
try: pr('market_overview', nm.market.get_market_overview(), 50000)
except Exception as e: print('market overview err', e)
try: pr('research list', nm.research.list_research_projects(), 60000)
except Exception as e: print('research list err', e)
try: pr('social API', nm.analytics.get_social_posts(days=14, limit=120), 50000)
except Exception as e: print('social err', e)
for gid in ['S2','S3','D_S07','D_E02','D_E09','S1']:
    try: pr(f'insights {gid}', nm.market.get_group_insights(group_id=gid), 30000)
    except Exception as e: print('insight err', gid, e)

